{t:'Effect Scatter',d:'Animated ripple scatter for emphasis',f:1,o:{tooltip:{trigger:'item'},xAxis:{type:'value'},yAxis:{type:'value'},series:[{type:'scatter',data:[[10,10],[15,20],[20,15],[25,30],[30,25],[35,40],[40,35],[45,50],[50,45],[55,60]],symbolSize:10,itemStyle:{color:C.primary}},{type:'effectScatter',rippleEffect:{brushType:'stroke',scale:4},data:[[25,30],[50,45]],symbolSize:18,itemStyle:{color:C.danger}}],grid:{left:50,right:20,top:20,bottom:30}}},
{t:'Punch Card of Github',d:'Day × hour bubble matrix',f:1,tall:1,o:function(){var hours=['12a','1a','2a','3a','4a','5a','6a','7a','8a','9a','10a','11a','12p','1p','2p','3p','4p','5p','6p','7p','8p','9p','10p','11p'];var days=['Sat','Fri','Thu','Wed','Tue','Mon','Sun'];var data=[];for(var d=0;d<7;d++)for(var h=0;h<24;h++){var v=0;if(h>=8&&h<=17)v=Math.round(Math.random()*12+2);else if(h>=18&&h<=22)v=Math.round(Math.random()*5);else v=Math.round(Math.random()*2);if(d===0||d===6)v=Math.round(v*0.4);data.push([h,d,v])}return{tooltip:{formatter:function(p){return days[p.value[1]]+' '+hours[p.value[0]]+'<br/>Commits: '+p.value[2]}},xAxis:{type:'category',data:hours,splitArea:{show:true}},yAxis:{type:'category',data:days,splitArea:{show:true}},series:[{type:'scatter',data:data,symbolSize:function(val){return val[2]*2.5},itemStyle:{color:C.primary+'cc'}}],grid:{left:50,right:20,top:10,bottom:30},visualMap:{show:false,min:0,max:15,inRange:{color:[C.primary+'22',C.primary]}}}}()},
{t:'Scatter on Single Axis',d:'Scatter distributed on a single value axis',f:1,o:{tooltip:{},xAxis:{},yAxis:{type:'category',data:['A','B','C']},series:[{type:'scatter',data:[[10,'A'],[20,'A'],[30,'A'],[15,'B'],[25,'B'],[35,'B'],[45,'B'],[12,'C'],[22,'C'],[33,'C']],symbolSize:14,itemStyle:{color:C.primary}}],grid:{left:30,right:20,top:20,bottom:30}}},
{t:'Scatter + VisualMap',d:'Color mapped to value range',f:1,o:function(){var data=[];for(var i=0;i<80;i++)data.push([Math.random()*100,Math.random()*100,Math.round(Math.random()*100)]);return{tooltip:{formatter:function(p){return'Score: '+p.value[2]}},xAxis:{type:'value'},yAxis:{type:'value'},visualMap:{min:0,max:100,dimension:2,inRange:{color:['#eff6ff','#3b82f6','#1e3a8a']},right:10,top:'center',text:['High','Low']},series:[{type:'scatter',data:data,symbolSize:function(v){return 6+v[2]/8}}],grid:{left:50,right:80,top:20,bottom:30}}}()},
{t:'Exponential Regression',d:'Scatter with fitted exponential curve',f:1,o:function(){var raw=[];for(var i=0;i<30;i++){var x=i*0.5;raw.push([x,Math.exp(x*0.15)*10+Math.random()*8-4])}var line=[];for(var x=0;x<15;x+=0.2)line.push([x,Math.exp(x*0.15)*10]);return{tooltip:{trigger:'item'},xAxis:{type:'value'},yAxis:{type:'value'},series:[{type:'scatter',data:raw,symbolSize:8,itemStyle:{color:C.primary}},{type:'line',data:line,showSymbol:false,lineStyle:{color:C.danger,width:2,type:'dashed'},smooth:true}],grid:{left:50,right:20,top:20,bottom:30}}}()},
{t:'Large Scatter',d:'5000 random data points',f:1,o:function(){var data=[];for(var i=0;i<5000;i++)data.push([Math.random()*1000,Math.random()*1000]);return{tooltip:{trigger:'item'},xAxis:{type:'value'},yAxis:{type:'value'},series:[{type:'scatter',data:data,symbolSize:3,itemStyle:{color:C.primary+'66'},large:true}],grid:{left:60,right:20,top:20,bottom:30}}}()}
