{t:'Geo Scatter (Pattern)',d:'Scatter points on coordinate plane as geo proxy',f:1,o:function(){var cities=[{name:'New York',xy:[74,41],v:8336},{name:'London',xy:[51,51.5],v:8982},{name:'Tokyo',xy:[140,36],v:13960},{name:'Sydney',xy:[151,-34],v:5312},{name:'Dubai',xy:[55,25],v:3331},{name:'Singapore',xy:[104,1.3],v:5686}];return{tooltip:{trigger:'item',formatter:function(p){return p.name+'<br/>Pop: '+p.value[2]+'K'}},xAxis:{type:'value',name:'Longitude',min:-20,max:180},yAxis:{type:'value',name:'Latitude',min:-50,max:70},series:[{type:'effectScatter',data:cities.map(function(c){return{name:c.name,value:[c.xy[0],c.xy[1],c.v]}}),symbolSize:function(v){return Math.sqrt(v[2])*0.5},rippleEffect:{brushType:'stroke'},label:{show:true,formatter:'{b}',position:'right',fontSize:11},itemStyle:{color:C.primary}}],grid:{left:60,right:30,top:20,bottom:50}}}()},
