{t:'Hexagonal Binning',d:'Density visualization using hex grid pattern',f:1,o:function(){var data=[];for(var i=0;i<200;i++){var a=Math.random()*Math.PI*2;var r=Math.random()*40+10;data.push([50+r*Math.cos(a)+Math.random()*10,50+r*Math.sin(a)+Math.random()*10,Math.round(Math.random()*10)])}return{tooltip:{},xAxis:{type:'value',min:0,max:100},yAxis:{type:'value',min:0,max:100},visualMap:{min:0,max:10,inRange:{color:['#eff6ff','#3b82f6','#1e3a8a']},show:false},series:[{type:'scatter',data:data,symbolSize:8,itemStyle:{opacity:0.7}}],grid:{left:40,right:20,top:20,bottom:30}}}()}
