{t:'Candlestick + MA',d:'K-line with moving average overlays',f:1,tall:1,o:function(){var raw=[[20,34,10,38],[40,35,30,50],[31,38,33,44],[38,15,5,42],[20,34,10,38],[40,35,30,50],[31,38,33,44],[38,15,5,42],[25,40,15,45],[35,30,25,48],[28,42,20,50],[45,38,30,52],[30,35,22,40],[42,48,35,55],[38,32,28,45]];var cl=raw.map(function(d){return d[1]});function ma(a,n){var r=[];for(var i=0;i<a.length;i++){if(i<n-1)r.push('-');else{var s=0;for(var j=0;j<n;j++)s+=a[i-j];r.push(+(s/n).toFixed(1))}}return r}var days=[];for(var i=1;i<=15;i++)days.push('Mar '+i);return{tooltip:{trigger:'axis',axisPointer:{type:'cross'}},legend:{data:['K-Line','MA5','MA10'],bottom:0},xAxis:{type:'category',data:days},yAxis:{type:'value',scale:true},series:[{name:'K-Line',type:'candlestick',data:raw,itemStyle:{color:C.success,color0:C.danger,borderColor:C.success,borderColor0:C.danger}},{name:'MA5',type:'line',data:ma(cl,5),smooth:true,lineStyle:{width:2,color:C.secondary},showSymbol:false},{name:'MA10',type:'line',data:ma(cl,10),smooth:true,lineStyle:{width:2,color:C.warning},showSymbol:false}],grid:{left:60,right:20,top:20,bottom:40}}}()},
{t:'Large Scale Candlestick',d:'100 data points with DataZoom',f:1,tall:1,o:function(){var data=[];var base=100;var days=[];for(var i=0;i<100;i++){days.push('Day '+(i+1));var o=base;var c=o+(Math.random()-0.48)*10;var h=Math.max(o,c)+(Math.random()*5);var l=Math.min(o,c)-(Math.random()*5);data.push([+o.toFixed(1),+c.toFixed(1),+l.toFixed(1),+h.toFixed(1)]);base=c}return{tooltip:{trigger:'axis',axisPointer:{type:'cross'}},xAxis:{type:'category',data:days},yAxis:{type:'value',scale:true},dataZoom:[{type:'slider',start:60,end:100},{type:'inside'}],series:[{type:'candlestick',data:data,itemStyle:{color:C.success,color0:C.danger,borderColor:C.success,borderColor0:C.danger}}],grid:{left:60,right:20,top:20,bottom:80}}}()},
{t:'Candlestick with Volume',d:'K-line with volume bars below',f:1,tall:1,o:function(){var raw=[];var vol=[];var base=50;var days=[];for(var i=0;i<30;i++){days.push('D'+(i+1));var o=base;var c=o+(Math.random()-0.48)*6;var h=Math.max(o,c)+Math.random()*3;var l=Math.min(o,c)-Math.random()*3;raw.push([+o.toFixed(1),+c.toFixed(1),+l.toFixed(1),+h.toFixed(1)]);vol.push(Math.round(Math.random()*5000+1000));base=c}return{tooltip:{trigger:'axis',axisPointer:{type:'cross'}},xAxis:[{type:'category',data:days,gridIndex:0},{type:'category',data:days,gridIndex:1}],yAxis:[{type:'value',scale:true,gridIndex:0},{type:'value',gridIndex:1}],grid:[{left:60,right:20,top:20,height:'55%'},{left:60,right:20,top:'75%',height:'15%'}],series:[{type:'candlestick',data:raw,xAxisIndex:0,yAxisIndex:0,itemStyle:{color:C.success,color0:C.danger,borderColor:C.success,borderColor0:C.danger}},{type:'bar',data:vol,xAxisIndex:1,yAxisIndex:1,color:C.info+'88',barWidth:'60%'}]}}()}
],
