boxplot:[
{t:'Basic Boxplot',d:'Box-and-whisker with outliers',f:1,o:function(){function rnd(min,max,n){var a=[];for(var i=0;i<n;i++)a.push(+(min+Math.random()*(max-min)).toFixed(1));return a.sort(function(x,y){return x-y})}function stats(arr){var q1=arr[Math.floor(arr.length*.25)],med=arr[Math.floor(arr.length*.5)],q3=arr[Math.floor(arr.length*.75)],iqr=q3-q1;return[Math.max(arr[0],q1-1.5*iqr),q1,med,q3,Math.min(arr[arr.length-1],q3+1.5*iqr)]}var labels=['Mon','Tue','Wed','Thu','Fri'];var raw=labels.map(function(){return rnd(10,90,30)});var boxData=raw.map(stats);var outliers=[];raw.forEach(function(d,i){var s=boxData[i];d.forEach(function(v){if(v<s[0]||v>s[4])outliers.push([i,v])})});return{tooltip:{trigger:'item'},xAxis:{type:'category',data:labels},yAxis:{type:'value'},series:[{type:'boxplot',data:boxData,itemStyle:{color:'#eff6ff',borderColor:C.secondary,borderWidth:2}},{type:'scatter',data:outliers,symbolSize:6,itemStyle:{color:C.danger}}],grid:{left:50,right:20,top:20,bottom:30}}}()},
{t:'Boxplot Horizontal',d:'Horizontal box plot orientation',f:1,o:function(){var labels=['Group A','Group B','Group C','Group D'];function rnd(n){var a=[];for(var i=0;i<n;i++)a.push(+(Math.random()*80+10).toFixed(1));return a.sort(function(x,y){return x-y})}function stats(arr){var q1=arr[Math.floor(arr.length*.25)],med=arr[Math.floor(arr.length*.5)],q3=arr[Math.floor(arr.length*.75)],iqr=q3-q1;return[Math.max(arr[0],q1-1.5*iqr),q1,med,q3,Math.min(arr[arr.length-1],q3+1.5*iqr)]}var raw=labels.map(function(){return rnd(40)});return{tooltip:{trigger:'item'},yAxis:{type:'category',data:labels},xAxis:{type:'value'},series:[{type:'boxplot',data:raw.map(stats),itemStyle:{color:'#fef3c7',borderColor:C.warning,borderWidth:2}}],grid:{left:80,right:20,top:20,bottom:30}}}()},
{t:'Multiple Categories',d:'Comparing distributions across groups',f:1,o:function(){function genBox(){var a=[];for(var i=0;i<25;i++)a.push(+(Math.random()*60+20).toFixed(1));a.sort(function(x,y){return x-y});var q1=a[6],med=a[12],q3=a[18],iqr=q3-q1;return[Math.max(a[0],q1-1.5*iqr),q1,med,q3,Math.min(a[24],q3+1.5*iqr)]}var cats=['Jan','Feb','Mar','Apr','May','Jun'];return{tooltip:{trigger:'item'},legend:{data:['Product A','Product B'],bottom:0},xAxis:{type:'category',data:cats},yAxis:{type:'value'},series:[{name:'Product A',type:'boxplot',data:cats.map(genBox),itemStyle:{borderColor:P[0],color:P[0]+'22'}},{name:'Product B',type:'boxplot',data:cats.map(genBox),itemStyle:{borderColor:P[1],color:P[1]+'22'}}],grid:{left:50,right:20,top:20,bottom:40}}}()},
