],
heatmap:[
{t:'Heatmap on Cartesian',d:'Grid-based heatmap (hour × day)',f:1,o:function(){var h=['12a','1a','2a','3a','4a','5a','6a','7a','8a','9a','10a','11a','12p','1p','2p','3p','4p','5p','6p','7p','8p','9p','10p','11p'];var d=['Sat','Fri','Thu','Wed','Tue','Mon','Sun'];var data=[];for(var i=0;i<7;i++)for(var j=0;j<24;j++)data.push([j,i,Math.round(Math.random()*10)]);return{tooltip:{position:'top'},xAxis:{type:'category',data:h,splitArea:{show:true}},yAxis:{type:'category',data:d,splitArea:{show:true}},visualMap:{min:0,max:10,calculable:true,orient:'horizontal',left:'center',bottom:0,inRange:{color:['#eff6ff','#bfdbfe','#3b82f6','#1e40af']}},series:[{type:'heatmap',data:data,label:{show:true,fontSize:10}}],grid:{left:50,right:20,top:10,bottom:60}}}()},
{t:'Heatmap 20K Data',d:'Large heatmap with 20000 data points',f:1,tall:1,o:function(){var data=[];for(var i=0;i<100;i++)for(var j=0;j<200;j++)data.push([j,i,Math.round(Math.random()*100)/10]);var xData=[],yData=[];for(var i=0;i<200;i++)xData.push(i);for(var i=0;i<100;i++)yData.push(i);return{tooltip:{position:'top'},xAxis:{type:'category',data:xData,show:false},yAxis:{type:'category',data:yData,show:false},visualMap:{min:0,max:10,calculable:true,orient:'horizontal',left:'center',bottom:0,inRange:{color:['#313695','#4575b4','#74add1','#abd9e9','#fee090','#fdae61','#f46d43','#d73027']}},series:[{type:'heatmap',data:data,progressive:5000,animation:false}],grid:{left:10,right:10,top:10,bottom:50}}}()},
{t:'Discrete Mapping',d:'Heatmap with discrete color categories',f:1,o:function(){var days=['Mon','Tue','Wed','Thu','Fri'];var hours=['9am','10am','11am','12pm','1pm','2pm','3pm','4pm','5pm'];var data=[];for(var i=0;i<5;i++)for(var j=0;j<9;j++)data.push([j,i,Math.floor(Math.random()*4)]);return{tooltip:{formatter:function(p){return days[p.value[1]]+' '+hours[p.value[0]]+'<br/>Level: '+['Low','Medium','High','Critical'][p.value[2]]}},xAxis:{type:'category',data:hours,splitArea:{show:true}},yAxis:{type:'category',data:days,splitArea:{show:true}},visualMap:{type:'piecewise',min:0,max:3,categories:['Low','Medium','High','Critical'],inRange:{color:['#dcfce7','#fef9c3','#fed7aa','#fecaca']},orient:'horizontal',left:'center',bottom:0},series:[{type:'heatmap',data:data,label:{show:true,formatter:function(p){return['Low','Med','High','Crit'][p.value[2]]},fontSize:10}}],grid:{left:50,right:20,top:10,bottom:60}}}()},
{t:'Calendar Heatmap',d:'GitHub-style contribution graph (365 days)',f:1,tall:1,o:function(){var data=[];var d=new Date(2025,0,1);for(var i=0;i<365;i++){var cur=new Date(d.getTime()+i*86400000);var val=Math.round(Math.random()*10);if(cur.getDay()===0||cur.getDay()===6)val=Math.round(val*0.4);data.push([cur.getFullYear()+'/'+(cur.getMonth()+1)+'/'+cur.getDate(),val])}return{tooltip:{formatter:function(p){return p.value[0]+'<br/>Commits: '+p.value[1]}},visualMap:{min:0,max:10,type:'piecewise',orient:'horizontal',left:'center',bottom:0,pieces:[{min:0,max:0,color:'#ebedf0'},{min:1,max:3,color:'#9be9a8'},{min:4,max:6,color:'#40c463'},{min:7,max:9,color:'#30a14e'},{min:10,max:10,color:'#216e39'}]},calendar:{top:40,left:50,right:30,cellSize:['auto',14],range:'2025',itemStyle:{borderWidth:3,borderColor:'#fff'},yearLabel:{show:true},dayLabel:{firstDay:1,nameMap:'en'},monthLabel:{nameMap:'en'}},series:[{type:'heatmap',coordinateSystem:'calendar',data:data}]}}()},
{t:'Calendar Heatmap Vertical',d:'Vertical orientation calendar heatmap',f:1,tall:1,o:function(){var data=[];var d=new Date(2025,0,1);for(var i=0;i<180;i++){var cur=new Date(d.getTime()+i*86400000);data.push([cur.getFullYear()+'/'+(cur.getMonth()+1)+'/'+cur.getDate(),Math.round(Math.random()*100)])}return{tooltip:{},visualMap:{min:0,max:100,orient:'horizontal',left:'center',bottom:0,inRange:{color:['#ebedf0','#bfdbfe','#3b82f6','#1e3a8a']}},calendar:{top:40,left:80,orient:'vertical',cellSize:[14,'auto'],range:'2025-01/2025-06',yearLabel:{show:true},dayLabel:{firstDay:1},monthLabel:{nameMap:'en',margin:10}},series:[{type:'heatmap',coordinateSystem:'calendar',data:data}]}}()}
],
graph:[
{t:'Force Layout',d:'Force-directed node-link network',f:1,o:{tooltip:{},series:[{type:'graph',layout:'force',roam:true,force:{repulsion:200,edgeLength:[50,150]},data:[{name:'Server',symbolSize:60,itemStyle:{color:C.primary}},{name:'DB',symbolSize:45,itemStyle:{color:C.secondary}},{name:'Cache',symbolSize:40,itemStyle:{color:C.success}},{name:'API',symbolSize:50,itemStyle:{color:C.warning}},{name:'Web',symbolSize:45,itemStyle:{color:C.info}},{name:'Worker',symbolSize:35,itemStyle:{color:'#8b5cf6'}},{name:'CDN',symbolSize:30,itemStyle:{color:'#ec4899'}},{name:'Queue',symbolSize:35,itemStyle:{color:'#14b8a6'}}],links:[{source:'Web',target:'API'},{source:'API',target:'Server'},{source:'Server',target:'DB'},{source:'Server',target:'Cache'},{source:'API',target:'Queue'},{source:'Queue',target:'Worker'},{source:'Web',target:'CDN'},{source:'Worker',target:'DB'}],label:{show:true,fontSize:12},lineStyle:{color:'#cbd5e1',curveness:.1}}]}},
{t:'Simple Graph',d:'Basic graph with fixed positions',f:1,o:{tooltip:{},series:[{type:'graph',layout:'none',roam:true,data:[{name:'A',x:100,y:100,symbolSize:40,itemStyle:{color:P[0]}},{name:'B',x:250,y:50,symbolSize:35,itemStyle:{color:P[1]}},{name:'C',x:250,y:150,symbolSize:35,itemStyle:{color:P[2]}},{name:'D',x:400,y:100,symbolSize:30,itemStyle:{color:P[3]}}],links:[{source:'A',target:'B'},{source:'A',target:'C'},{source:'B',target:'D'},{source:'C',target:'D'}],label:{show:true,fontSize:14,fontWeight:'bold'},lineStyle:{color:'#94a3b8',width:2}}]}},
{t:'Circular Layout',d:'Nodes arranged in a circle',f:1,o:function(){var nodes=[];var links=[];var names=['Alpha','Beta','Gamma','Delta','Epsilon','Zeta','Eta','Theta'];for(var i=0;i<8;i++){nodes.push({name:names[i],symbolSize:30+Math.random()*20,itemStyle:{color:P[i%8]}});for(var j=i+1;j<8;j++){if(Math.random()>0.5)links.push({source:names[i],target:names[j]})}}return{tooltip:{},series:[{type:'graph',layout:'circular',circular:{rotateLabel:true},roam:true,data:nodes,links:links,label:{show:true,fontSize:11},lineStyle:{color:'#cbd5e1',curveness:.3,opacity:.6}}]}}()},
{t:'Graph on Cartesian',d:'Graph overlaid on XY coordinate system',f:1,o:{tooltip:{},xAxis:{type:'value',min:0,max:10},yAxis:{type:'value',min:0,max:10},series:[{type:'graph',layout:'none',coordinateSystem:'cartesian2d',data:[{name:'Start',value:[1,5],symbolSize:40,itemStyle:{color:P[0]}},{name:'Step 1',value:[3,8],symbolSize:35,itemStyle:{color:P[1]}},{name:'Step 2',value:[3,2],symbolSize:35,itemStyle:{color:P[2]}},{name:'Merge',value:[6,5],symbolSize:40,itemStyle:{color:P[3]}},{name:'End',value:[9,5],symbolSize:45,itemStyle:{color:P[4]}}],links:[{source:'Start',target:'Step 1'},{source:'Start',target:'Step 2'},{source:'Step 1',target:'Merge'},{source:'Step 2',target:'Merge'},{source:'Merge',target:'End'}],label:{show:true,fontSize:11},lineStyle:{color:'#94a3b8',width:2,curveness:0.1}}],grid:{left:40,right:20,top:20,bottom:30}}},
{t:'Les Miserables (Small)',d:'Community detection network visualization',f:1,tall:1,o:function(){var groups=[{names:['Valjean','Fantine','Cosette','Marius','Javert'],color:P[0]},{names:['Thenardier','Eponine','Gavroche','Enjolras','Combeferre'],color:P[1]},{names:['Bishop','Grantaire','Courfeyrac','Bahorel','Bossuet'],color:P[2]}];var nodes=[];var links=[];groups.forEach(function(g){g.names.forEach(function(n){nodes.push({name:n,symbolSize:15+Math.random()*25,itemStyle:{color:g.color},category:groups.indexOf(g)})})});var allNames=nodes.map(function(n){return n.name});for(var i=0;i<allNames.length;i++){var numLinks=Math.floor(Math.random()*3)+1;for(var j=0;j<numLinks;j++){var target=allNames[Math.floor(Math.random()*allNames.length)];if(target!==allNames[i])links.push({source:allNames[i],target:target})}}return{tooltip:{},legend:{data:['Group 1','Group 2','Group 3'],bottom:0},series:[{type:'graph',layout:'force',roam:true,force:{repulsion:120,edgeLength:[40,100]},categories:[{name:'Group 1'},{name:'Group 2'},{name:'Group 3'}],data:nodes,links:links,label:{show:true,fontSize:10,position:'right'},lineStyle:{color:'#cbd5e1',curveness:.2,opacity:.4}}]}}()},
{t:'Dynamic Graph',d:'Graph with animated node addition',f:1,o:function(){var nodes=[{name:'Core',symbolSize:50,itemStyle:{color:C.primary},x:200,y:150}];var links=[];for(var i=1;i<=8;i++){var angle=i*Math.PI*2/8;nodes.push({name:'Node '+i,symbolSize:25+Math.random()*15,itemStyle:{color:P[i%8]},x:200+Math.cos(angle)*120,y:150+Math.sin(angle)*100});links.push({source:'Core',target:'Node '+i})}return{tooltip:{},animationDuration:2000,animationEasingUpdate:'quinticInOut',series:[{type:'graph',layout:'none',roam:true,data:nodes,links:links,label:{show:true,fontSize:11},lineStyle:{color:'#94a3b8',width:2,curveness:0}}]}}()},
{t:'Hide Overlapped Label',d:'Dense graph with auto label hiding',f:1,o:function(){var nodes=[];var links=[];for(var i=0;i<30;i++){nodes.push({name:'N'+i,symbolSize:10+Math.random()*20,itemStyle:{color:P[i%8]}});if(i>0)links.push({source:'N'+Math.floor(Math.random()*i),target:'N'+i})}return{tooltip:{},series:[{type:'graph',layout:'force',roam:true,force:{repulsion:80,edgeLength:[30,80]},data:nodes,links:links,label:{show:true,fontSize:9},labelLayout:{hideOverlap:true},lineStyle:{color:'#e2e8f0',opacity:.5}}]}}()}
],
