{t:'Clock Gauge',d:'Animated clock with three hands',f:1,o:function(){var n=new Date();return{series:[{type:'gauge',startAngle:90,endAngle:-270,min:0,max:12,splitNumber:12,clockwise:true,axisLine:{lineStyle:{width:2,color:[[1,'#e2e8f0']]}},axisTick:{length:4,lineStyle:{color:'#94a3b8'}},splitLine:{length:10,lineStyle:{width:2,color:'#64748b'}},axisLabel:{fontSize:14,color:'#374151',distance:16,formatter:function(v){return v===0?'':v}},pointer:{icon:'path://M2.9,0.7L2.9,-0.7L0.6,-0.7L0.6,-6L-0.6,-6L-0.6,-0.7L-2.9,-0.7L-2.9,0.7Z',width:6,length:'55%',itemStyle:{color:'#1e293b'}},anchor:{show:true,size:12,itemStyle:{color:'#1e293b',borderWidth:2,borderColor:'#fff'}},detail:{show:false},data:[{value:n.getHours()%12+n.getMinutes()/60}]},{type:'gauge',startAngle:90,endAngle:-270,min:0,max:60,clockwise:true,axisLine:{show:false},axisTick:{show:false},splitLine:{show:false},axisLabel:{show:false},pointer:{icon:'path://M2.9,0.7L2.9,-0.7L0.6,-0.7L0.6,-6L-0.6,-6L-0.6,-0.7L-2.9,-0.7L-2.9,0.7Z',width:4,length:'70%',itemStyle:{color:C.primary}},detail:{show:false},data:[{value:n.getMinutes()+n.getSeconds()/60}]},{type:'gauge',startAngle:90,endAngle:-270,min:0,max:60,clockwise:true,axisLine:{show:false},axisTick:{show:false},splitLine:{show:false},axisLabel:{show:false},pointer:{icon:'path://M2,0.5L2,-0.5L0.3,-0.5L0.3,-6L-0.3,-6L-0.3,-0.5L-2,-0.5L-2,0.5Z',width:2,length:'80%',itemStyle:{color:C.danger}},detail:{show:false},data:[{value:n.getSeconds()}]}]}}()}
