{t:'ThemeRiver (Multi-Stream)',d:'5 streams over 2 years',f:1,tall:1,o:function(){var streams=['JS','Python','Java','Go','Rust'];var data=[];for(var y=2024;y<=2025;y++){for(var m=1;m<=12;m++){var dt=y+'/'+m;streams.forEach(function(s,i){data.push([dt,Math.round(Math.random()*30+10+i*5),s])})}}return{tooltip:{trigger:'axis'},singleAxis:{type:'time',top:40,bottom:40},series:[{type:'themeRiver',data:data,label:{show:false},emphasis:{focus:'self'},itemStyle:{borderWidth:1,borderColor:'#fff'}}]}}()}
