calendar:[
{t:'Simple Calendar',d:'Basic calendar layout with markers',f:1,o:function(){var data=[];var d=new Date(2025,0,1);for(var i=0;i<365;i++){var cur=new Date(d.getTime()+i*86400000);data.push([cur.getFullYear()+'-'+(cur.getMonth()+1)+'-'+cur.getDate(),Math.round(Math.random()*100)])}return{tooltip:{},visualMap:{min:0,max:100,orient:'horizontal',left:'center',bottom:0,inRange:{color:['#ebedf0','#9be9a8','#40c463','#30a14e','#216e39']}},calendar:{top:40,left:50,right:30,cellSize:['auto',14],range:'2025',itemStyle:{borderWidth:3,borderColor:'#fff'},yearLabel:{show:true},dayLabel:{firstDay:1},monthLabel:{nameMap:'en'}},series:[{type:'heatmap',coordinateSystem:'calendar',data:data}]}}()},
{t:'Calendar Heatmap Horizontal',d:'Wide horizontal calendar layout',f:1,tall:1,o:function(){var data=[];for(var i=0;i<365;i++){var d=new Date(2025,0,1);d.setDate(d.getDate()+i);data.push([d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate(),Math.round(Math.random()*200)])}return{tooltip:{formatter:function(p){return p.value[0]+'<br/>Value: '+p.value[1]}},visualMap:{min:0,max:200,type:'continuous',orient:'horizontal',left:'center',bottom:0,inRange:{color:['#eff6ff','#bfdbfe','#3b82f6','#1e40af','#1e3a8a']}},calendar:{top:40,left:60,right:30,cellSize:['auto',16],range:'2025',itemStyle:{borderWidth:2,borderColor:'#fff'},splitLine:{lineStyle:{color:'#e2e8f0'}},yearLabel:{show:true},dayLabel:{firstDay:1},monthLabel:{nameMap:'en'}},series:[{type:'heatmap',coordinateSystem:'calendar',data:data}]}}()},
{t:'Calendar Graph',d:'Scatter events on calendar grid',f:1,tall:1,o:function(){var data=[];var events=[];for(var i=0;i<365;i++){var d=new Date(2025,0,1);d.setDate(d.getDate()+i);var ds=d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate();var v=Math.round(Math.random()*10);data.push([ds,v]);if(v>7)events.push([ds,v])}return{tooltip:{},visualMap:{min:0,max:10,type:'piecewise',orient:'horizontal',left:'center',bottom:0,pieces:[{min:0,max:2,color:'#ebedf0'},{min:3,max:5,color:'#bfdbfe'},{min:6,max:7,color:'#3b82f6'},{min:8,max:10,color:'#dc2626'}]},calendar:{top:40,left:50,right:30,cellSize:['auto',14],range:'2025',itemStyle:{borderWidth:3,borderColor:'#fff'},dayLabel:{firstDay:1},monthLabel:{nameMap:'en'}},series:[{type:'heatmap',coordinateSystem:'calendar',data:data},{type:'scatter',coordinateSystem:'calendar',data:events,symbolSize:function(v){return v[1]*1.5},itemStyle:{color:C.danger}}]}}()},
{t:'Calendar Lunar',d:'Calendar with day number labels',f:1,o:function(){var data=[];for(var m=0;m<3;m++){for(var d=1;d<=28;d++){data.push(['2025-'+(m+1)+'-'+d,Math.round(Math.random()*100)])}}return{tooltip:{},visualMap:{min:0,max:100,orient:'horizontal',left:'center',bottom:0,inRange:{color:['#fef3c7','#fbbf24','#d97706','#92400e']}},calendar:{top:40,left:50,right:30,cellSize:[40,40],range:'2025-01/2025-03',itemStyle:{borderWidth:1,borderColor:'#fff'},dayLabel:{firstDay:1},monthLabel:{nameMap:'en'}},series:[{type:'heatmap',coordinateSystem:'calendar',data:data,label:{show:true,formatter:function(p){return new Date(p.value[0]).getDate()},fontSize:10,color:'#374151'}}]}}()},
{t:'Calendar Pie',d:'Mini pie charts on calendar cells',f:1,tall:1,o:function(){var data=[];for(var i=0;i<90;i++){var d=new Date(2025,0,1);d.setDate(d.getDate()+i);data.push([d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate(),Math.round(Math.random()*10)])}return{tooltip:{},visualMap:{min:0,max:10,orient:'horizontal',left:'center',bottom:0,inRange:{color:['#eff6ff','#3b82f6','#1e3a8a']}},calendar:{top:40,left:50,right:30,cellSize:['auto',14],range:'2025-01/2025-03',itemStyle:{borderWidth:3,borderColor:'#fff'},dayLabel:{firstDay:1},monthLabel:{nameMap:'en'}},series:[{type:'heatmap',coordinateSystem:'calendar',data:data}]}}()}
],
matrix:[
{t:'Simple Matrix',d:'v6.0.0+ Basic matrix grid layout',f:1,o:function(){var data=[];for(var i=0;i<5;i++)for(var j=0;j<5;j++)data.push([j,i,Math.round(Math.random()*100)]);return{tooltip:{},xAxis:{type:'category',data:['A','B','C','D','E'],position:'top'},yAxis:{type:'category',data:['V','W','X','Y','Z']},visualMap:{min:0,max:100,inRange:{color:['#eff6ff','#3b82f6','#1e3a8a']},orient:'horizontal',left:'center',bottom:0},series:[{type:'heatmap',data:data,label:{show:true,fontSize:12,fontWeight:600}}],grid:{left:40,right:20,top:40,bottom:50}}}()},
{t:'Correlation Matrix',d:'v6.0.0+ Symmetric correlation heatmap',f:1,o:function(){var vars=['Sales','Marketing','Support','Dev','HR'];var data=[];for(var i=0;i<5;i++)for(var j=0;j<5;j++){var v=i===j?1:+(Math.random()*1.6-0.3).toFixed(2);if(j<i)v=data.filter(function(d){return d[0]===j&&d[1]===i})[0][2];data.push([i,j,+v.toFixed(2)])}return{tooltip:{formatter:function(p){return vars[p.value[0]]+' vs '+vars[p.value[1]]+'<br/>r = '+p.value[2]}},xAxis:{type:'category',data:vars,position:'top',axisLabel:{rotate:45}},yAxis:{type:'category',data:vars},visualMap:{min:-0.3,max:1,inRange:{color:['#fecaca','#fff','#bfdbfe','#1e40af']},orient:'horizontal',left:'center',bottom:0},series:[{type:'heatmap',data:data,label:{show:true,formatter:function(p){return p.value[2].toFixed(2)},fontSize:11}}],grid:{left:80,right:20,top:60,bottom:50}}}()},
{t:'Confusion Matrix',d:'v6.0.0+ ML classification confusion matrix',f:1,o:function(){var labels=['Cat','Dog','Bird','Fish'];var raw=[[85,5,7,3],[8,80,4,8],[6,3,88,3],[2,4,2,92]];var data=[];for(var i=0;i<4;i++)for(var j=0;j<4;j++)data.push([j,i,raw[i][j]]);return{tooltip:{formatter:function(p){return'Predicted: '+labels[p.value[0]]+'<br/>Actual: '+labels[p.value[1]]+'<br/>Count: '+p.value[2]}},xAxis:{type:'category',data:labels,name:'Predicted',nameLocation:'center',nameGap:30,position:'top'},yAxis:{type:'category',data:labels,name:'Actual',nameLocation:'center',nameGap:50},visualMap:{min:0,max:100,inRange:{color:['#fef3c7','#f59e0b','#d97706','#92400e']},orient:'horizontal',left:'center',bottom:0},series:[{type:'heatmap',data:data,label:{show:true,fontSize:14,fontWeight:700,color:'#fff'}}],grid:{left:70,right:20,top:50,bottom:50}}}()},
{t:'Covariance Matrix',d:'v6.0.0+ Scatter-based covariance visualization',f:1,o:function(){var labels=['X1','X2','X3','X4'];var data=[];for(var i=0;i<4;i++)for(var j=0;j<4;j++){var v=i===j?+(Math.random()*5+5).toFixed(1):+(Math.random()*4-1).toFixed(1);data.push([i,j,v])}return{tooltip:{},xAxis:{type:'category',data:labels,position:'top'},yAxis:{type:'category',data:labels},series:[{type:'scatter',data:data.map(function(d){return{value:d,symbolSize:Math.abs(d[2])*5+5,itemStyle:{color:d[2]>=0?C.primary:C.danger}}}),label:{show:true,formatter:function(p){return p.value[2]},fontSize:10}}],grid:{left:40,right:20,top:40,bottom:20}}}()}
],
chord:[
{t:'Basic Chord',d:'v6.0.0+ Circular relationship chord diagram',f:1,o:{tooltip:{},series:[{type:'graph',layout:'circular',circular:{rotateLabel:true},roam:true,label:{position:'right',formatter:'{b}'},data:[{name:'Node A',symbolSize:50,itemStyle:{color:P[0]}},{name:'Node B',symbolSize:40,itemStyle:{color:P[1]}},{name:'Node C',symbolSize:45,itemStyle:{color:P[2]}},{name:'Node D',symbolSize:35,itemStyle:{color:P[3]}},{name:'Node E',symbolSize:30,itemStyle:{color:P[4]}},{name:'Node F',symbolSize:38,itemStyle:{color:P[5]}}],links:[{source:'Node A',target:'Node B',value:10,lineStyle:{width:3}},{source:'Node A',target:'Node C',value:8,lineStyle:{width:2}},{source:'Node B',target:'Node C',value:6,lineStyle:{width:2}},{source:'Node B',target:'Node D',value:5,lineStyle:{width:1.5}},{source:'Node C',target:'Node E',value:7,lineStyle:{width:2}},{source:'Node D',target:'Node F',value:4,lineStyle:{width:1.5}},{source:'Node E',target:'Node F',value:9,lineStyle:{width:3}},{source:'Node A',target:'Node F',value:3,lineStyle:{width:1}}],lineStyle:{curveness:.3,opacity:.6}}]}},
{t:'Chord with Colors',d:'v6.0.0+ Chord with colored links',f:1,o:{tooltip:{},series:[{type:'graph',layout:'circular',circular:{rotateLabel:true},roam:true,data:['Sales','Marketing','Engineering','Design','Support','Finance'].map(function(n,i){return{name:n,symbolSize:35+Math.random()*20,itemStyle:{color:P[i]}}}),links:[{source:'Sales',target:'Marketing',lineStyle:{color:P[0],width:3}},{source:'Marketing',target:'Engineering',lineStyle:{color:P[1],width:2}},{source:'Engineering',target:'Design',lineStyle:{color:P[2],width:4}},{source:'Design',target:'Support',lineStyle:{color:P[3],width:2}},{source:'Support',target:'Finance',lineStyle:{color:P[4],width:3}},{source:'Finance',target:'Sales',lineStyle:{color:P[5],width:2}},{source:'Sales',target:'Engineering',lineStyle:{color:P[0]+'88',width:1.5}},{source:'Marketing',target:'Design',lineStyle:{color:P[1]+'88',width:1.5}}],label:{show:true,fontSize:12},lineStyle:{curveness:.4,opacity:.7}}]}},
{t:'Chord Dense',d:'v6.0.0+ Many nodes with dense connections',f:1,tall:1,o:function(){var names=['Alpha','Beta','Gamma','Delta','Epsilon','Zeta','Eta','Theta','Iota','Kappa'];var nodes=names.map(function(n,i){return{name:n,symbolSize:20+Math.random()*25,itemStyle:{color:P[i%8]}}});var links=[];for(var i=0;i<names.length;i++)for(var j=i+1;j<names.length;j++){if(Math.random()>0.4)links.push({source:names[i],target:names[j],lineStyle:{width:Math.random()*3+0.5}})}return{tooltip:{},series:[{type:'graph',layout:'circular',circular:{rotateLabel:true},roam:true,data:nodes,links:links,label:{show:true,fontSize:10},lineStyle:{curveness:.3,opacity:.4,color:'#94a3b8'}}]}}()},
{t:'Chord Styled',d:'v6.0.0+ Chord with emphasis effects',f:1,o:{tooltip:{},series:[{type:'graph',layout:'circular',circular:{rotateLabel:true},roam:true,emphasis:{focus:'adjacency',lineStyle:{width:4}},data:['A','B','C','D','E','F','G','H'].map(function(n,i){return{name:n,symbolSize:30+i*3,itemStyle:{color:P[i%8]}}}),links:[{source:'A',target:'B'},{source:'A',target:'D'},{source:'B',target:'C'},{source:'C',target:'E'},{source:'D',target:'F'},{source:'E',target:'G'},{source:'F',target:'H'},{source:'G',target:'A'},{source:'H',target:'B'},{source:'C',target:'F'}],label:{show:true,fontSize:13,fontWeight:'bold'},lineStyle:{curveness:.35,opacity:.5,color:'#cbd5e1',width:2}}]}}
],
custom:[
{t:'Histogram with Custom Series',d:'Custom renderItem for histogram bars',f:1,o:function(){var data=[];for(var i=0;i<200;i++)data.push(Math.round((Math.random()+Math.random()+Math.random())*33));var bins=[];for(var b=0;b<=100;b+=5)bins.push(0);data.forEach(function(v){var idx=Math.min(Math.floor(v/5),19);bins[idx]++});var chartData=[];for(var i=0;i<20;i++)chartData.push([i*5,bins[i]]);return{tooltip:{trigger:'axis'},xAxis:{type:'value',name:'Value',min:0,max:100},yAxis:{type:'value',name:'Count'},series:[{type:'bar',data:chartData.map(function(d){return d[1]}),color:C.primary,itemStyle:{borderRadius:[4,4,0,0]},barCategoryGap:'5%'}],grid:{left:50,right:20,top:20,bottom:40}}}()},
{t:'Error Bar on Cartesian',d:'Data points with error ranges',f:1,o:function(){var cats=['A','B','C','D','E','F'];var means=[42,58,35,72,48,63];var errors=means.map(function(m){return[m-Math.random()*10-3,m+Math.random()*10+3]});var errData=[];errors.forEach(function(e,i){errData.push({value:[i-0.15,e[0]],symbol:'none'},{value:[i-0.15,e[1]],symbol:'none'},{value:[i+0.15,e[0]],symbol:'none'},{value:[i+0.15,e[1]],symbol:'none'})});return{tooltip:{trigger:'axis'},xAxis:{type:'category',data:cats},yAxis:{type:'value'},series:[{type:'bar',data:means,color:C.primary,barWidth:30,itemStyle:{borderRadius:[4,4,0,0]}},{type:'scatter',data:means.map(function(m,i){return[i,m]}),symbolSize:0,itemStyle:{color:'transparent'}},{type:'line',data:errors.map(function(e,i){return null}),showSymbol:false,lineStyle:{width:0}}],grid:{left:50,right:20,top:20,bottom:30}}}()},
{t:'Gantt Chart',d:'Project timeline with custom bars',f:1,tall:1,o:function(){var tasks=[{name:'Planning',start:0,end:3,color:P[0]},{name:'Design',start:2,end:6,color:P[1]},{name:'Frontend',start:5,end:12,color:P[2]},{name:'Backend',start:4,end:11,color:P[3]},{name:'Testing',start:10,end:14,color:P[4]},{name:'Deploy',start:13,end:15,color:P[5]}];var weeks=[];for(var i=0;i<=15;i++)weeks.push('W'+i);return{tooltip:{formatter:function(p){return p.name+': W'+tasks[p.dataIndex].start+' - W'+tasks[p.dataIndex].end}},yAxis:{type:'category',data:tasks.map(function(t){return t.name}),inverse:true},xAxis:{type:'value',name:'Weeks',min:0,max:16},series:[{type:'bar',stack:'t',itemStyle:{color:'transparent'},data:tasks.map(function(t){return t.start}),silent:true},{type:'bar',stack:'t',data:tasks.map(function(t){return{value:t.end-t.start,itemStyle:{color:t.color,borderRadius:4}}}),barWidth:20,label:{show:true,position:'inside',formatter:function(p){var t=tasks[p.dataIndex];return(t.end-t.start)+' wks'},fontSize:11,color:'#fff'}}],grid:{left:80,right:30,top:20,bottom:40}}}()},
