{t:'Scatter3D Pattern',d:'3D scatter plot configuration',f:1,o:function(){var data=[];for(var i=0;i<100;i++)data.push([Math.random()*100,Math.random()*100]);return{tooltip:{trigger:'item'},xAxis:{type:'value',name:'X'},yAxis:{type:'value',name:'Y'},series:[{type:'scatter',data:data,symbolSize:8,itemStyle:{color:C.secondary+'88'}}],graphic:[{type:'text',left:'center',bottom:10,style:{text:'Use scatter3D with echarts-gl for true 3D scatter',fontSize:11,fill:'#94a3b8'}}],grid:{left:50,right:20,top:20,bottom:40}}}()},
{t:'Surface Pattern',d:'3D surface / parametric surface config',f:1,o:function(){var data=[];for(var x=-3;x<=3;x+=0.3)for(var y=-3;y<=3;y+=0.3){var z=Math.sin(Math.sqrt(x*x+y*y));data.push([(x+3)/6*100,(y+3)/6*100,z])}return{tooltip:{},xAxis:{type:'value',show:false},yAxis:{type:'value',show:false},visualMap:{min:-1,max:1,inRange:{color:['#1e3a8a','#3b82f6','#93c5fd','#fde68a','#f97316','#dc2626']},show:false},series:[{type:'scatter',data:data,symbolSize:4}],graphic:[{type:'text',left:'center',bottom:10,style:{text:'Use surfaceGL with echarts-gl for true 3D surfaces',fontSize:11,fill:'#94a3b8'}}],grid:{left:10,right:10,top:10,bottom:30}}}()},
{t:'Lines3D / Flights Pattern',d:'3D line / flight path configuration',f:1,o:function(){var cities=[{name:'NYC',xy:[25,65]},{name:'London',xy:[48,60]},{name:'Tokyo',xy:[85,55]},{name:'Sydney',xy:[82,25]},{name:'Dubai',xy:[60,50]},{name:'Singapore',xy:[75,40]}];var links=[['NYC','London'],['London','Dubai'],['Dubai','Singapore'],['Singapore','Tokyo'],['Tokyo','Sydney'],['NYC','Tokyo']];return{tooltip:{trigger:'item'},xAxis:{type:'value',show:false,min:0,max:100},yAxis:{type:'value',show:false,min:0,max:100},series:[{type:'effectScatter',data:cities.map(function(c){return{name:c.name,value:c.xy}}),symbolSize:12,rippleEffect:{brushType:'stroke'},label:{show:true,formatter:'{b}',position:'top',fontSize:11},itemStyle:{color:C.primary}},{type:'lines',coordinateSystem:'cartesian2d',data:links.map(function(l){var from=cities.find(function(c){return c.name===l[0]});var to=cities.find(function(c){return c.name===l[1]});return{coords:[from.xy,to.xy]}}),lineStyle:{color:C.primary+'66',width:2,curveness:0.2},effect:{show:true,trailLength:0.2,symbol:'arrow',symbolSize:6,color:C.primary}}],graphic:[{type:'text',left:'center',bottom:10,style:{text:'Use lines3D with echarts-gl for 3D globe flights',fontSize:11,fill:'#94a3b8'}}],grid:{left:10,right:10,top:10,bottom:30}}}()},
{t:'GraphGL Pattern',d:'GPU-accelerated large graph layout',f:1,o:function(){var nodes=[];var links=[];for(var i=0;i<50;i++){nodes.push({name:'N'+i,symbolSize:6+Math.random()*12,itemStyle:{color:P[i%8]}});if(i>0){links.push({source:'N'+Math.floor(Math.random()*i),target:'N'+i});if(Math.random()>0.6)links.push({source:'N'+Math.floor(Math.random()*i),target:'N'+i})}}return{tooltip:{},series:[{type:'graph',layout:'force',roam:true,force:{repulsion:50,edgeLength:[20,60]},data:nodes,links:links,label:{show:false},lineStyle:{color:'#e2e8f0',opacity:.4}}],graphic:[{type:'text',left:'center',bottom:10,style:{text:'Use graphGL for 10K+ node GPU-accelerated layouts',fontSize:11,fill:'#94a3b8'}}]}}()}
]
};

var tab='{{ $activeTab }}';
var charts=CHARTS[tab]||[];
var grid=document.getElementById('chartGrid');
var instances=[];

function esc(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}
function toggleCode(id,btn){var el=document.getElementById(id);el.classList.toggle('show');btn.classList.toggle('open');btn.textContent=el.classList.contains('show')?'Hide Code':'View Code'}

charts.forEach(function(c,i){
    var id='ch_'+tab+'_'+i;
    var fc=c.f?' full':'';
    var hc=c.tall?' tall':'';
    var code;try{code=typeof c.o==='function'?'(dynamic)':JSON.stringify(c.o,function(k,v){return typeof v==='function'?'[Function]':v},2)}catch(e){code='(unable to serialize)'}
    grid.innerHTML+='<div class="chart-card'+fc+'"><div class="chart-card-head"><div><div class="chart-card-title">'+c.t+'</div><div class="chart-card-desc">'+c.d+'</div></div><button class="btn-code" onclick="toggleCode(\'code_'+id+'\',this)">View Code</button></div><div id="'+id+'" class="chart-box'+hc+'"></div><div id="code_'+id+'" class="code-block">'+esc(code)+'</div></div>';
});

charts.forEach(function(c,i){
    var id='ch_'+tab+'_'+i;
    var el=document.getElementById(id);
    if(!el)return;
    try{
        var inst=echarts.init(el);
        inst.setOption(c.o);
        instances.push(inst);
    }catch(e){
        el.innerHTML='<div style="display:flex;align-items:center;justify-content:center;height:100%;flex-direction:column;color:var(--c-primary,#dc2626);font-size:13px;padding:20px;text-align:center"><i class="fas fa-exclamation-triangle" style="font-size:24px;margin-bottom:8px;color:#f59e0b"></i><b>Chart failed to render</b><div style="color:#64748b;margin-top:6px;font-size:12px;word-break:break-all">'+c.t+': '+e.message+'</div></div>';
        console.error('Chart error ['+c.t+']:',e);
    }
});

window.addEventListener('resize',function(){instances.forEach(function(inst){if(!inst.isDisposed())inst.resize()})});

});
</script>
